canvas.init:
function init(canvas, params) {
  var ctx = canvas.getContext('2d');
  var N = params.particles || 300;
  var trail = params.trail != null ? params.trail : 0.2;
  var style = getComputedStyle(canvas);
  var bg = style.getPropertyValue('--ct-bg-deep').trim() || '#1a050b';
  var color = style.getPropertyValue('--ct-text-strong').trim() || '#ffffff';
  var ps = Array.from({ length: N }, function() {
    return {
      angle: Math.random() * Math.PI * 2,
      radius: Math.random() * 150,
      speed: Math.random() * 0.03 + 0.01,
      size: Math.random() * 1.5 + 0.5
    };
  });
  function hexToRgba(h, a) {
    h = h.replace('#','');
    if (h.length === 3) h = h.split('').map(function(c){return c+c;}).join('');
    var r = parseInt(h.slice(0,2),16), g = parseInt(h.slice(2,4),16), b = parseInt(h.slice(4,6),16);
    return 'rgba('+r+','+g+','+b+','+a+')';
  }
  function draw() {
    ctx.fillStyle = hexToRgba(bg, trail);
    ctx.fillRect(0, 0, 300, 180);
    var cx = 150, cy = 90;
    ps.forEach(function(p) {
      p.angle += p.speed;
      p.radius -= p.speed * 5;
      if (p.radius < 5) { p.radius = 150; p.angle = Math.random() * Math.PI * 2; }
      var x = cx + Math.cos(p.angle) * p.radius;
      var y = cy + Math.sin(p.angle) * p.radius;
      ctx.fillStyle = hexToRgba(color, Math.min(1, p.radius / 50));
      ctx.beginPath(); ctx.arc(x, y, p.size, 0, Math.PI * 2); ctx.fill();
    });
    requestAnimationFrame(draw);
  }
  draw();
}
